import type { DBClient } from '../db';
import { basename } from 'path';

type Optional<T> = T | undefined;
type QueryDTO = Record<string, any> & {
  limit?: number;
  skip?: number;
  sort?: { [key: string]: 'ASC' | 'DESC' };
};

export abstract class BaseDao<Model, DTO> {
  constructor(protected prismaClient: DBClient) {}

  get prisma() {
    return this.prismaClient;
  }

  idSelector(id: number) {
    return { where: { id } };
  }

  getResourceIdFromPath(path: string) {
    return Number(basename(path));
  }

  parseQuery<DTO extends QueryDTO>(dto: DTO) {
    const query = structuredClone(dto);

    delete query.limit;
    delete query.skip;
    delete query.sort;

    return {
      take: dto.limit ?? 10,
      skip: dto.skip ?? 0,
      orderBy: dto.sort ?? undefined,
      data: query
    };
  }

  abstract toDTO(entity: Model): DTO;
  abstract toPersistance(entity: DTO): Partial<Model>;
}

import { Container, Inject, Injectable } from '@decorators/di';
import { BaseDao } from './base.dao';
import { PostFile } from '@prisma/client';
import { DBClient } from '../db';
import { PostFileDTO } from '../dto/post-file.dto';
import { ROUTES } from '../config';

@Injectable()
export class PostFileDao extends BaseDao<PostFile, any> {
  constructor(@Inject('PrismaClient') private client: DBClient) {
    super(client);
  }

  getById(id: number) {
    return this.client.postFile.findFirst(this.idSelector(id));
  }

  toDTO(entity: PostFile): PostFileDTO {
    return {
      self: `${ROUTES.POSTS}/${entity.postId}/files/${entity.id}`,
      post: `${ROUTES.POSTS}/${entity.postId}`,
      media: `${ROUTES.POSTS}/${entity.postId}/files/${entity.id}/content`,
      encoding: entity.encoding,
      filename: entity.filename,
      original_filename: entity.original_filename,
      mime: entity.mime,
      size: entity.size,
      createdAt: entity.createdAt,
      updatedAt: entity.updatedAt
    };
  }
  toPersistance(entity: any): Partial<PostFile> {
    throw new Error('Method not implemented.');
  }
}

Container.provide([{ provide: 'PostFileDao', useClass: PostFileDao }]);

