import { Container, Inject, Injectable } from '@decorators/di';
import { BaseDao } from './base.dao';
import { PostTag } from '@prisma/client';
import { DBClient } from '../db';
import { PostTagDTO } from '../dto/post-tag.dto';
import { PostTagAssociation } from '../interfaces';
import { ROUTES } from '../config';
import { TagDao } from './tag.dao';

@Injectable()
export class PostTagDao extends BaseDao<PostTag, any> {
  constructor(
    @Inject('PrismaClient') private client: DBClient,
    @Inject('TagDao') private tagDao: TagDao
  ) {
    super(client);
  }

  async create(postId: number, tagId: number) {
    return this.client.postTag.create({
      data: { postId, tagId },
      include: { tags: true }
    }) as unknown as PostTagAssociation;
  }

  async delete(postId: number, tagId: number) {
    return this.client.postTag.delete({
      where: { postId_tagId: { postId, tagId } }
    });
  }

  find(postId: number, tagId: number) {
    return this.client.postTag.findFirst({
      where: {
        postId,
        tagId
      },
      include: { tags: true }
    }) as unknown as PostTagAssociation;
  }

  toDTO(entity: PostTagAssociation): PostTagDTO {
    return {
      post: `${ROUTES.POSTS}/${entity.postId}`,
      tag: `${ROUTES.TAGS}/${entity.tagId}`,
      value: entity.tags.label,
      createdAt: entity.createdAt,
      updatedAt: entity.updatedAt
    };
  }
  toPersistance(entity: PostTagDTO): Partial<PostTag> {
    throw new Error('Method not implemented.');
  }
}

Container.provide([{ provide: 'PostTagDao', useClass: PostTagDao }]);

import { ZodObject, ZodRawShape, z, ZodError } from 'zod';
import { Request, Response, NextFunction } from 'express';
import { BadRequestError } from '../utilities/errors.util';

export function ZodBodyValidator<T extends ZodRawShape>(schema: ZodObject<T>) {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      req.body = schema.parse(req.body);
      next();
    } catch (err) {
      let message = 'Validation Failed';
      let details: any = {};

      if (err instanceof ZodError) {
        message = `Validation failed: ${err.issues.length} errors detected in body`;
        details = err.issues;
      }

      const badReqError = new BadRequestError(message);
      badReqError.details = details;

      next(badReqError);
    }
  };
}

export function ZodQueryValidator<T extends ZodRawShape>(schema: ZodObject<T>) {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      req.query = schema.parse(req.query);
      next();
    } catch (err) {
      let message = 'Query Format Error';
      let details: any = {};

      if (err instanceof ZodError) {
        message = err.message;
        details = err.issues;
      }

      const badReqError = new BadRequestError(message);
      badReqError.details = details;

      next(badReqError);
    }
  };
}

export function ZodParamValidator<T extends ZodRawShape>(schema: ZodObject<T>) {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      req.params = schema.parse(req.params);
      next();
    } catch (err) {
      let message = 'Query Format Error';
      let details: any = {};

      if (err instanceof ZodError) {
        message = err.message;
        details = err.issues;
      }

      const badReqError = new BadRequestError(message);
      badReqError.details = details;

      next(badReqError);
    }
  };
}

export function ZodIdValidator(idField = 'id') {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      req.params[idField] = z
        .number({ coerce: true })
        .parse(req.params[idField]) as any;
      next();
    } catch (err) {
      let message = 'Query Format Error';
      let details: any = {};

      if (err instanceof ZodError) {
        message = err.message;
        details = err.issues;
      }

      const badReqError = new BadRequestError(message);
      badReqError.details = details;

      next(badReqError);
    }
  };
}

import { Container } from '@decorators/di';

type tempLevels = 'info';

interface ILoggerService<Levels extends string> {
  log: (level: Levels, message: string, metadata?: Record<string, any>) => void;
  error: (error: Error) => void;
}

export class LoggerService implements ILoggerService<tempLevels> {
  log(level: tempLevels, message: string, metadata?: Record<string, any>) {
    const metadataStr = metadata ? JSON.stringify(metadata) : '';

    console.log(
      `[${new Date().toISOString()}] [${level.toUpperCase()}] ${message} ${metadataStr}`
    );
  }

  error(error: Error) {
    this.log('info', error.message);

    if (error.stack) {
      console.log(error.stack);
    }
  }
}

Container.provide([{ provide: 'LoggerService', useClass: LoggerService }]);

export default new LoggerService();

export class HTTPError extends Error {
  code: number;
  details: Record<string, any>;

  constructor(
    message: string,
    code: number,
    details: Record<string, any> = {}
  ) {
    super(message);
    this.code = code;
    this.details = details;
  }
}

export class BadRequestError extends HTTPError {
  name = 'BadRequestError';

  constructor(message: string) {
    super(message, 400);
  }
}

export class UnauthorizedError extends HTTPError {
  name = 'UnauthorizedError';

  constructor(message: string) {
    super(message, 401);
  }
}

export class ForbiddenError extends HTTPError {
  name = 'ForbiddenError';

  constructor(message: string) {
    super(message, 403);
  }
}

export class NotFoundError extends HTTPError {
  name = 'NotFoundError';

  constructor(message: string) {
    super(message, 404);
  }
}

export class UnprocessableError extends HTTPError {
  name = 'UnprocessableError';

  constructor(message: string) {
    super(message, 422);
  }
}

export class GeneralError extends HTTPError {
  name = 'GeneralError';

  constructor(message: string) {
    super(message, 500);
  }
}
